      doses:[{route:'Oral',dose:'500–1000 mg',freq:'Cada 6–8 h',max:'4000 mg/día'},{route:'IM/IV',dose:'1000–2000 mg',freq:'Cada 6–8 h',max:'5000 mg/día (IV lenta)'},{route:'Supositorio',dose:'1000 mg',freq:'Cada 8 h',max:'3000 mg/día'}],
